  const neighbors = this.countNeighbors(x, y);
  const isAlive = this.cellExists(x, y);

  if (isAlive) {
    // Survival rule: live cell survives with 2 or 3 neighbors
    return neighbors >= GameOfLife.MIN_SURVIVAL_NEIGHBORS &&
           neighbors <= GameOfLife.MAX_SURVIVAL_NEIGHBORS;
  } else {
    // Reproduction rule: dead cell becomes alive with exactly 3 neighbors
    return neighbors === 3;
  }
}

