  if (this.cells.length === 0) {
    return [];
  }

  const result: [number, number][] = [];

  // Check survival of all live cells
  for (const [x, y] of this.cells) {
    if (this.shouldCellExist(x, y)) {
      result.push([x, y]);
    }
  }

  // Check resurrection of dead cells with exactly 3 neighbors
  // We check cells adjacent to all live cells
  const cellsToCheck = new Set<string>();
  for (const [x, y] of this.cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        const nx = x + dx;
        const ny = y + dy;
        cellsToCheck.add(`${nx},${ny}`);
      }
    }
  }

  for (const coord of cellsToCheck) {
    const [x, y] = coord.split(',').map(Number);
    if (!this.cellExists(x, y) && this.shouldCellExist(x, y)) {
      result.push([x, y]);
    }
  }

  return result;
}

